import json
import os
from channels.generic.websocket import AsyncWebsocketConsumer
from ollama import AsyncClient

OLLAMA_HOST = os.environ.get('OLLAMA_HOST', 'http://localhost:11434')
OLLAMA_MODEL = os.environ.get('OLLAMA_MODEL', 'qwen2.5:7b')


class ChatConsumer(AsyncWebsocketConsumer):
    async def connect(self):
        await self.accept()
        # Optionally, you can send a welcome message
        await self.send(text_data=json.dumps({
            'type': 'system',
            'message': 'Connected to Ollama chat'
        }))

    async def disconnect(self, close_code):
        pass

    async def receive(self, text_data):
        try:
            data = json.loads(text_data)
            message = data.get('message', '').strip()
            if not message:
                return

            # Initialize Ollama client
            client = AsyncClient(host=OLLAMA_HOST)

            # Stream the response from Ollama
            async for part in client.chat(
                model=OLLAMA_MODEL,
                messages=[{'role': 'user', 'content': message}],
                stream=True,
            ):
                chunk = part.get('message', {}).get('content', '')
                if chunk:
                    await self.send(text_data=json.dumps({
                        'type': 'chunk',
                        'content': chunk
                    }))

            # Send a done signal
            await self.send(text_data=json.dumps({
                'type': 'done',
                'message': ''
            }))
        except Exception as e:
            await self.send(text_data=json.dumps({
                'type': 'error',
                'message': str(e)
            }))

{% extends "base.html" %}
{% block title %}Ollama Chat{% endblock %}
{% block content %}
<div class="container mx-auto p-4">
    <h1 class="text-2xl font-bold mb-4">Ollama Chat</h1>
    <div id="chat-messages" class="bg-white rounded-lg shadow-md p-4 mb-4 h-[60vh] overflow-y-auto">
        <!-- Messages will be appended here -->
    </div>
    <form id="chat-form">
        <div class="flex gap-2">
            <input type="text" name="message" id="chat-input" class="flex-1 p-2 border rounded" placeholder="Type a message..." required>
            <button type="submit" class="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600">Send</button>
        </div>
    </form>
</div>
<script>
    const chatMessagesDiv = document.getElementById('chat-messages');
    const chatForm = document.getElementById('chat-form');
    const chatInput = document.getElementById('chat-input');

    // WebSocket connection
    const ws = new WebSocket(`$(window.location.protocol === 'https:' ? 'wss' : 'ws')://${window.location.host}/ws/chat/`);

    ws.onopen = function() {
        console.log('WebSocket connected');
    };

    ws.onmessage = function(event) {
        const data = JSON.parse(event.data);
        if (data.type === 'chunk') {
            // Append chunk to the last message or create a new message div
            let lastMessageDiv = chatMessagesDiv.lastElementChild;
            if (!lastMessageDiv || !lastMessageDiv.classList.contains('message-bubble')) {
                lastMessageDiv = document.createElement('div');
                lastMessageDiv.className = 'message-bubble bg-blue-50 p-2 rounded mb-2';
                chatMessagesDiv.appendChild(lastMessageDiv);
            }
            lastMessageDiv.textContent += data.content;
            // Scroll to bottom
            chatMessagesDiv.scrollTop = chatMessagesDiv.scrollHeight;
        } else if (data.type === 'done') {
            // Optionally, add a separator or do nothing
        } else if (data.type === 'error') {
            const errorDiv = document.createElement('div');
            errorDiv.className = 'text-red-500 p-2';
            errorDiv.textContent = `Error: ${data.message}`;
            chatMessagesDiv.appendChild(errorDiv);
            chatMessagesDiv.scrollTop = chatMessagesDiv.scrollHeight;
        } else if (data.type === 'system') {
            const sysDiv = document.createElement('div');
            sysDiv.className = 'text-gray-500 italic p-2';
            sysDiv.textContent = data.message;
            chatMessagesDiv.appendChild(sysDiv);
            chatMessagesDiv.scrollTop = chatMessagesDiv.scrollHeight;
        }
    };

    ws.onclose = function() {
        console.log('WebSocket disconnected');
    };

    ws.onerror = function(error) {
        console.error('WebSocket error:', error);
    };

    // Handle form submission
    chatForm.addEventListener('submit', function(e) {
        e.preventDefault();
        const message = chatInput.value.trim();
        if (message && ws.readyState === WebSocket.OPEN) {
            ws.send(JSON.stringify({message: message}));
            chatInput.value = '';
        }
    });
</script>
